function workerCount(){if($('workers')?.value&&$('workers').value!=='auto')return Number($('workers').value);return(navigator.hardwareConcurrency||4)>=6?2:1}
async function createOcrWorkers(){const n=workerCount();st(`กำลังโหลด OCR ${n} worker...`);ocrWorkers=[];for(let i=0;i<n;i++){const w=await window.Tesseract.createWorker('tha+eng',1,{logger:m=>{if(m.status==='recognizing text')st(`OCR ${Math.round((m.progress||0)*100)}%`)}});ocrWorkers.push(w)}return ocrWorkers}
