function prepBadgeRegion(badge,y0,y1=.98,scale=6){const r={x:0,y:badge.height*y0,w:badge.width,h:badge.height*(y1-y0)},c=crop(badge,r,0),o=prepForOcr(c,scale,1);freeCanvas(c);return o}
async function recognizeBadge(worker,info){let calls=0,firstCanvas=prepBadgeRegion(info.badge,.12),first=await ocrCanvas(worker,firstCanvas,8,'0123456789%');freeCanvas(firstCanvas);calls++;let pct=parseBadgePercent(first.raw),second=null;if(pct===null){const c=prepBadgeRegion(info.badge,.18);second=await ocrCanvas(worker,c,8,'0123456789%');freeCanvas(c);calls++;pct=parseBadgePercent(second.raw)}let top=null,topNumbers=[];if(info.topInk>.22){const c=crop(info.badge,{x:0,y:0,w:info.badge.width,h:info.badge.height*.38},0),o=prepForOcr(c,8,1);freeCanvas(c);top=await ocrCanvas(worker,o,11,'0123456789-');freeCanvas(o);calls++;topNumbers=[...top.raw.matchAll(/\d+/g)].map(m=>Number(m[0]))}await worker.setParameters({tessedit_pageseg_mode:'11',tessedit_char_whitelist:''});if(pct===null)return{first,second,top,selected:second||first,label:'',valid:false,calls,method:'badge'};const same=FUNCTION_TEMPLATES.filter(t=>pctSig(t).at(-1)===pct);let label='';if(info.topInk<=.22||!topNumbers.length){const simple=`ลด ${pct}%`;label=FUNCTION_TEMPLATES.includes(simple)?simple:(same.length===1?same[0]:'')}else{const score=t=>{const q=quantitySig(t),tiers=parseTiers(t);let s=0;if(top.raw.includes('-')&&tiers[0]?.[0]==='range')s+=3;s+=2*lcs(topNumbers,q)/Math.max(1,topNumbers.length,q.length)-.2*Math.abs(topNumbers.length-q.length);if(pctSig(t).length===1)s+=1;return s};label=[...same].sort((a,b)=>score(b)-score(a))[0]||''}const confidence=Math.max(first.confidence,second?.confidence||0,top?.confidence||0),valid=!!label&&confidence>=50;return{first,second,top,selected:second||first,label,valid,calls,method:'badge',topInk:info.topInk}}
async function recognizeGeneral(worker,benefit){const firstCanvas=prepForOcr(benefit,4,1.45),firstOcr=await ocrCanvas(worker,firstCanvas,11,''),firstMatch=bestTemplate(firstOcr.raw);freeCanvas(firstCanvas);const first={...firstOcr,...firstMatch};let second=null,calls=1;if(first.confidence<78||first.score<.80||first.margin<.05){const psm=pctSig(first.raw).length?6:13,c=prepForOcr(benefit,4,1.7),o=await ocrCanvas(worker,c,psm,'');freeCanvas(c);second={...o,...bestTemplate(o.raw)};calls++}const candidates=[first,...(second?[second]:[])],selected=[...candidates].sort((a,b)=>b.score-a.score||b.margin-a.margin||b.confidence-a.confidence)[0],exact=parseTiers(selected.raw).length&&JSON.stringify(parseTiers(selected.raw))===JSON.stringify(parseTiers(selected.label)),strong=selected.score>=.90&&selected.margin>=.08&&selected.confidence>=72;await worker.setParameters({tessedit_pageseg_mode:'11',tessedit_char_whitelist:''});return{first,second,top:null,selected,label:selected.label,valid:!!(exact||strong),calls,method:'general'}}
